/* ============================================================
   PASO 7 - CRUD Catalogo.Cancion
   ============================================================ */

CREATE PROCEDURE Procesos.sp_InsertarCancion
    @tituloCancion   VARCHAR(50),
    @duracionCancion FLOAT,
    @idiomaCancion   VARCHAR(50) = NULL,
    @Genero_idGenero INT,
    @Album_idAlbum   INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @Genero_idGenero)
        THROW 50218, 'El genero especificado no existe.', 1;
    IF @Album_idAlbum IS NOT NULL AND NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @Album_idAlbum)
        THROW 50219, 'El album especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE tituloCancion = @tituloCancion AND Genero_idGenero = @Genero_idGenero)
        THROW 50220, 'Ya existe una cancion con ese titulo en el mismo genero.', 1;
    DECLARE @idCancion INT;
    SELECT @idCancion = ISNULL(MAX(idCancion), 0) + 1 FROM Catalogo.Cancion;
    VALUES (@idCancion, @tituloCancion, @duracionCancion, @idiomaCancion, @Genero_idGenero, @Album_idAlbum);
    SELECT 'Cancion registrada correctamente' AS Mensaje, @idCancion AS idCancion;
END;
GO

CREATE PROCEDURE Procesos.sp_ConsultarCanciones
    @idCancion INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT c.idCancion, c.tituloCancion, c.duracionCancion,
           ISNULL(c.idiomaCancion, '-') AS idiomaCancion,
           g.nombreGenero,
           ISNULL(a.tituloAlbum, '-') AS tituloAlbum
    FROM Catalogo.Cancion c
    INNER JOIN Catalogo.Genero g ON c.Genero_idGenero = g.idGenero
    LEFT  JOIN Catalogo.Album  a ON c.Album_idAlbum   = a.idAlbum
    WHERE (@idCancion IS NULL OR c.idCancion = @idCancion);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarCancion
    @idCancion       INT,
    @tituloCancion   VARCHAR(50),
    @duracionCancion FLOAT,
    @idiomaCancion   VARCHAR(50) = NULL,
    @Genero_idGenero INT,
    @Album_idAlbum   INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE idCancion = @idCancion)
        THROW 50221, 'La cancion especificada no existe.', 1;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Genero WHERE idGenero = @Genero_idGenero)
        THROW 50222, 'El genero especificado no existe.', 1;
    IF @Album_idAlbum IS NOT NULL AND NOT EXISTS (SELECT 1 FROM Catalogo.Album WHERE idAlbum = @Album_idAlbum)
        THROW 50223, 'El album especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE tituloCancion = @tituloCancion AND Genero_idGenero = @Genero_idGenero AND idCancion != @idCancion)
        THROW 50224, 'Ya existe otra cancion con ese titulo en el mismo genero.', 1;
    UPDATE Catalogo.Cancion
    SET tituloCancion = @tituloCancion, duracionCancion = @duracionCancion,
        idiomaCancion = @idiomaCancion, Genero_idGenero = @Genero_idGenero, Album_idAlbum = @Album_idAlbum
    WHERE idCancion = @idCancion;
    SELECT 'Cancion actualizada correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarCancion
    @idCancion INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Cancion WHERE idCancion = @idCancion)
        THROW 50221, 'La cancion especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Interaccion.ArtistaCancion WHERE Cancion_idCancion = @idCancion)
        THROW 50222, 'No se puede eliminar: la cancion tiene artistas asociados.', 1;
    DELETE FROM Interaccion.CancionPlaylist  WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Interaccion.UsuarioCancion   WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Interaccion.Reproduccion     WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Finanzas.Regalia             WHERE Cancion_idCancion = @idCancion;
    DELETE FROM Catalogo.Cancion             WHERE idCancion         = @idCancion;
    SELECT 'Cancion eliminada correctamente' AS Mensaje;
END;
GO


