CREATE PROCEDURE Procesos.sp_ConsultarUsuarios
    @idUsuario INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT idUsuario, nombreUsuario, apellidoUsuario,
           ISNULL(segundoNombreUsuario, '-')   AS segundoNombreUsuario,
           ISNULL(segundoApellidoUsuario, '-') AS segundoApellidoUsuario,
           correoUsuario, fechaRegistroUsuario
    FROM Seguridad.Usuario
    WHERE (@idUsuario IS NULL OR idUsuario = @idUsuario);
END;
GO

CREATE PROCEDURE Procesos.sp_ActualizarUsuario
    @idUsuario               INT,
    @nombreUsuario           VARCHAR(50),
    @apellidoUsuario         VARCHAR(50),
    @segundoNombreUsuario    VARCHAR(50) = NULL,
    @segundoApellidoUsuario  VARCHAR(50) = NULL,
    @correoUsuario           VARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE idUsuario = @idUsuario)
        THROW 50223, 'El usuario especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE correoUsuario = @correoUsuario AND idUsuario != @idUsuario)
        THROW 50224, 'El correo ya esta en uso por otro usuario.', 1;
    UPDATE Seguridad.Usuario
    SET nombreUsuario = @nombreUsuario, apellidoUsuario = @apellidoUsuario,
        segundoNombreUsuario = @segundoNombreUsuario, segundoApellidoUsuario = @segundoApellidoUsuario,
        correoUsuario = @correoUsuario
    WHERE idUsuario = @idUsuario;
    SELECT 'Usuario actualizado correctamente' AS Mensaje;
END;
GO

CREATE PROCEDURE Procesos.sp_EliminarUsuario
    @idUsuario INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE idUsuario = @idUsuario)
        THROW 50225, 'El usuario especificado no existe.', 1;
    IF EXISTS (SELECT 1 FROM Finanzas.Suscripcion WHERE Usuario_idUsuario = @idUsuario)
        THROW 50226, 'No se puede eliminar: el usuario tiene suscripciones activas.', 1;
    DELETE FROM Interaccion.UsuarioCancion  WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.UsuarioArtista  WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.Reproduccion    WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Interaccion.Playlist        WHERE Usuario_idUsuario = @idUsuario;
    DELETE FROM Seguridad.Usuario           WHERE idUsuario         = @idUsuario;
    SELECT 'Usuario eliminado correctamente' AS Mensaje;
END;
GO


