CREATE PROCEDURE Procesos.sp_ActualizarSuscripcion
    @idSuscripcion       INT,
    @tipoPlanSuscripcion VARCHAR(50),
    @fechaFinSuscripcion DATE = NULL,
    @estadoSuscripcion   VARCHAR(50) = NULL
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Finanzas.Suscripcion WHERE idSuscripcion = @idSuscripcion)
        THROW 50233, 'La suscripcion especificada no existe.', 1;
    IF @tipoPlanSuscripcion NOT IN ('Gratis', 'Premium')
        THROW 50234, 'El tipo de plan debe ser Gratis o Premium.', 1;
    IF @estadoSuscripcion IS NOT NULL AND @estadoSuscripcion NOT IN ('Activa', 'Cancelada', 'Vencida')
        THROW 50235, 'El estado debe ser Activa, Cancelada o Vencida.', 1;
    UPDATE Finanzas.Suscripcion
    SET tipoPlanSuscripcion = @tipoPlanSuscripcion,
        fechaFinSuscripcion = @fechaFinSuscripcion,
        estadoSuscripcion   = @estadoSuscripcion
    WHERE idSuscripcion = @idSuscripcion;
    SELECT 'Suscripcion actualizada correctamente' AS Mensaje;
END;
