/* -- 
   SonoraInc — Cierre de Gaps para Interfaz Web (Fase 4)
   Ejecutar sobre la BD SonoraInc ya creada y poblada.
   Orden recomendado: ejecutar sección por sección.
   --  */

USE SonoraInc;
GO

/* -- 
   GAP 1 — Login con contraseña (passwordHash)
   Problema : sp_IniciarSesion valida solo por correo.
              Cualquier persona con un email registrado entra.
   Solución : 1) Agregar columna passwordHash a Usuario.
              2) Poblar hashes de prueba (SHA2_256 simple para BD;
                 en producción Python envía el hash bcrypt).
              3) Reemplazar sp_IniciarSesion para validar el hash.
              4) Ajustar sp_RegistrarUsuario para recibir la clave.
   --  */

-- 1a. Agregar columna (NULL al inicio para no romper datos existentes)
ALTER TABLE Seguridad.Usuario
    ADD passwordHash VARCHAR(255) NULL;
GO

-- 1b. Poblar hashes de prueba en los 120 usuarios existentes.
--     Patrón: password es "Sonora" + idUsuario (ej: "Sonora1", "Sonora2"…)
--     En producción Python calculará bcrypt antes de llamar al SP.
UPDATE Seguridad.Usuario
SET passwordHash = CONVERT(VARCHAR(64),
        HASHBYTES('SHA2_256', 'Sonora' + CAST(idUsuario AS VARCHAR)), 2);
GO

-- Verificación rápida
-- SELECT TOP 3 idUsuario, correoUsuario, passwordHash FROM Seguridad.Usuario;

-- 1c. Constraint NOT NULL ahora que todos tienen hash
ALTER TABLE Seguridad.Usuario
    ALTER COLUMN passwordHash VARCHAR(255) NOT NULL;
GO


-- 1d. Reemplazar sp_IniciarSesion (valida correo + hash)
--     Python debe enviar: CONVERT(VARCHAR(64), HASHBYTES('SHA2_256', password), 2)
--     o el hash bcrypt cuando se migre a ese esquema.
DROP PROCEDURE IF EXISTS Procesos.sp_IniciarSesion;
GO

CREATE PROCEDURE Procesos.sp_IniciarSesion
    @correoUsuario  VARCHAR(50),
    @passwordHash   VARCHAR(255)        -- hash enviado desde Python
AS
BEGIN
    SET NOCOUNT ON;

    -- Verificar que el correo exista
    IF NOT EXISTS (
        SELECT 1 FROM Seguridad.Usuario
        WHERE correoUsuario = @correoUsuario
    )
    BEGIN
        THROW 50002, 'Credenciales incorrectas.', 1;
    END;

    -- Verificar contraseña
    IF NOT EXISTS (
        SELECT 1 FROM Seguridad.Usuario
        WHERE correoUsuario = @correoUsuario
          AND passwordHash  = @passwordHash
    )
    BEGIN
        -- Mismo mensaje que arriba para no revelar si el correo existe
        THROW 50002, 'Credenciales incorrectas.', 1;
    END;

    -- Devolver datos del usuario autenticado
    SELECT
        idUsuario,
        nombreUsuario,
        apellidoUsuario,
        correoUsuario,
        fechaRegistroUsuario
    FROM Seguridad.Usuario
    WHERE correoUsuario = @correoUsuario;
END;
GO


-- 1e. Reemplazar sp_RegistrarUsuario para recibir y guardar la contraseña
DROP PROCEDURE IF EXISTS Procesos.sp_RegistrarUsuario;
GO

CREATE PROCEDURE Procesos.sp_RegistrarUsuario
    @nombreUsuario          VARCHAR(50),
    @apellidoUsuario        VARCHAR(50),
    @segundoNombreUsuario   VARCHAR(50) = NULL,
    @segundoApellidoUsuario VARCHAR(50) = NULL,
    @correoUsuario          VARCHAR(50),
    @fechaRegistroUsuario   DATE,
    @passwordHash           VARCHAR(255)   -- hash SHA2_256 o bcrypt desde Python
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (
        SELECT 1 FROM Seguridad.Usuario
        WHERE correoUsuario = @correoUsuario
    )
    BEGIN
        THROW 50001, 'El correo ingresado ya se encuentra registrado.', 1;
    END;

    IF LEN(LTRIM(RTRIM(@passwordHash))) < 8
    BEGIN
        THROW 50030, 'El hash de contraseña no es válido.', 1;
    END;

    DECLARE @idUsuario INT;
    SELECT @idUsuario = ISNULL(MAX(idUsuario), 0) + 1
    FROM Seguridad.Usuario;

        idUsuario, nombreUsuario, apellidoUsuario,
        segundoNombreUsuario, segundoApellidoUsuario,
        correoUsuario, fechaRegistroUsuario, passwordHash
    )
    VALUES
    (
        @idUsuario, @nombreUsuario, @apellidoUsuario,
        @segundoNombreUsuario, @segundoApellidoUsuario,
        @correoUsuario, @fechaRegistroUsuario, @passwordHash
    );

    SELECT 'Usuario registrado correctamente' AS Mensaje, @idUsuario AS idUsuario;
END;
GO

