/* -- 
   GAP 2 — sp_CalcularRegaliasGlobal duplica registros
   Problema : El cursor inserta una nueva fila en Finanzas.Regalia
              por cada canción, cada vez que se ejecuta.
              Llamarlo dos veces duplica todos los registros.
   Solución : Antes de insertar, verificar si ya existe una regalia
              para esa canción en esa fecha; si existe, hacer UPDATE.
   --  */

DROP PROCEDURE IF EXISTS Procesos.sp_CalcularRegaliasGlobal;
GO

CREATE PROCEDURE Procesos.sp_CalcularRegaliasGlobal
    @valorPorReproduccion   DECIMAL(10,2),
    @fechaCalculoRegalia    DATE
AS
BEGIN
    SET NOCOUNT ON;

    IF @valorPorReproduccion <= 0
    BEGIN
        THROW 50040, 'El valor por reproducción debe ser mayor a cero.', 1;
    END;

    DECLARE @idCancion              INT;
    DECLARE @cantidadReproducciones INT;
    DECLARE @montoRegalia           DECIMAL(10,2);
    DECLARE @idRegalia              INT;
    DECLARE @insertados             INT = 0;
    DECLARE @actualizados           INT = 0;

    DECLARE cursorCanciones CURSOR FOR
        SELECT idCancion FROM Catalogo.Cancion;

    OPEN cursorCanciones;
    FETCH NEXT FROM cursorCanciones INTO @idCancion;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        -- Contar reproducciones de esta cancion
        SELECT @cantidadReproducciones = COUNT(*)
        FROM Interaccion.Reproduccion
        WHERE Cancion_idCancion = @idCancion;

        SET @montoRegalia = ISNULL(@cantidadReproducciones, 0) * @valorPorReproduccion;

        -- ¿Ya existe una regalia para esta cancion en esta fecha?
        IF EXISTS (
            SELECT 1 FROM Finanzas.Regalia
            WHERE Cancion_idCancion      = @idCancion
              AND fechaCalculoRegalia    = @fechaCalculoRegalia
        )
        BEGIN
            -- UPDATE en lugar de duplicar
            UPDATE Finanzas.Regalia
            SET cantidadReproduccionesRegalia = @cantidadReproducciones,
                montoGeneradoRegalia          = @montoRegalia
            WHERE Cancion_idCancion    = @idCancion
              AND fechaCalculoRegalia  = @fechaCalculoRegalia;

            SET @actualizados = @actualizados + 1;
        END
        ELSE
        BEGIN
            -- INSERT solo si no existe para esa fecha
            SELECT @idRegalia = ISNULL(MAX(idRegalia), 0) + 1
            FROM Finanzas.Regalia;

                idRegalia, cantidadReproduccionesRegalia,
                montoGeneradoRegalia, fechaCalculoRegalia, Cancion_idCancion
            )
            VALUES
            (
                @idRegalia, ISNULL(@cantidadReproducciones, 0),
                @montoRegalia, @fechaCalculoRegalia, @idCancion
            );

            SET @insertados = @insertados + 1;
        END;

        FETCH NEXT FROM cursorCanciones INTO @idCancion;
    END;

    CLOSE cursorCanciones;
    DEALLOCATE cursorCanciones;

    SELECT
        'Regalías calculadas correctamente' AS Mensaje,
        @insertados   AS NuevasInsertadas,
        @actualizados AS Actualizadas;
END;
GO

-- Verificación Gap 2
-- EXEC Procesos.sp_CalcularRegaliasGlobal 0.05, '2026-05-22';
-- EXEC Procesos.sp_CalcularRegaliasGlobal 0.05, '2026-05-22';  -- segunda vez no duplica
-- SELECT COUNT(*) FROM Finanzas.Regalia WHERE fechaCalculoRegalia = '2026-05-22';


/* -- 
   GAP 3 — IDs manuales (MAX+1) con race condition
   Problema : ISNULL(MAX(id), 0) + 1 falla bajo concurrencia:
              dos sesiones simultáneas pueden obtener el mismo ID
              antes de que ninguna haga el INSERT.
   Solución : Agregar columna IDENTITY a cada tabla y reasignar
              la generación de IDs a SQL Server.
              Los SPs dejan de calcular el ID manualmente.

   NOTA: Alterar una PK existente para hacerla IDENTITY requiere
   recrear la tabla. En un sistema en producción esto se haría
   con una migración planificada. Aquí el script muestra el
   patrón para UNA tabla (Seguridad.Usuario) como ejemplo
   demostrable; el mismo patrón aplica a las demás.

   Alternativa más simple para el proyecto (recomendada):
   Usar SEQUENCE objects — no requiere recrear tablas.
   --  */

-- 3a. Crear SEQUENCES para las tablas principales
--     (se sincronizan con el MAX actual para no colisionar con datos existentes)

-- Usuario
DECLARE @maxUsuario INT;
SELECT @maxUsuario = ISNULL(MAX(idUsuario), 0) + 1 FROM Seguridad.Usuario;
DECLARE @sqlU NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Usuario START WITH ' + CAST(@maxUsuario AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlU;
GO

-- Artista
DECLARE @maxArtista INT;
SELECT @maxArtista = ISNULL(MAX(idArtista), 0) + 1 FROM Catalogo.Artista;
DECLARE @sqlA NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Artista START WITH ' + CAST(@maxArtista AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlA;
GO

-- Cancion
DECLARE @maxCancion INT;
SELECT @maxCancion = ISNULL(MAX(idCancion), 0) + 1 FROM Catalogo.Cancion;
DECLARE @sqlC NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Cancion START WITH ' + CAST(@maxCancion AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlC;
GO

-- Playlist
DECLARE @maxPlaylist INT;
SELECT @maxPlaylist = ISNULL(MAX(idPlaylist), 0) + 1 FROM Interaccion.Playlist;
DECLARE @sqlPL NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Playlist START WITH ' + CAST(@maxPlaylist AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlPL;
GO

-- Reproduccion
DECLARE @maxRepr INT;
SELECT @maxRepr = ISNULL(MAX(idReproduccion), 0) + 1 FROM Interaccion.Reproduccion;
DECLARE @sqlR NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Reproduccion START WITH ' + CAST(@maxRepr AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlR;
GO

-- Suscripcion
DECLARE @maxSusc INT;
SELECT @maxSusc = ISNULL(MAX(idSuscripcion), 0) + 1 FROM Finanzas.Suscripcion;
DECLARE @sqlS NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Suscripcion START WITH ' + CAST(@maxSusc AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlS;
GO

-- Pago
DECLARE @maxPago INT;
SELECT @maxPago = ISNULL(MAX(idPago), 0) + 1 FROM Finanzas.Pago;
DECLARE @sqlPG NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Pago START WITH ' + CAST(@maxPago AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlPG;
GO

-- Regalia
DECLARE @maxReg INT;
SELECT @maxReg = ISNULL(MAX(idRegalia), 0) + 1 FROM Finanzas.Regalia;
DECLARE @sqlRG NVARCHAR(500) =
    N'CREATE SEQUENCE dbo.seq_Regalia START WITH ' + CAST(@maxReg AS NVARCHAR) +
    N' INCREMENT BY 1 MINVALUE 1 NO MAXVALUE NO CYCLE NO CACHE;';
EXEC sp_executesql @sqlRG;
GO


-- 3b. Reemplazar SPs clave para usar NEXT VALUE FOR en lugar de MAX+1

-- sp_RegistrarUsuario ya fue reemplazado en Gap 1. 
-- Actualizar únicamente la línea de generación de ID:
DROP PROCEDURE IF EXISTS Procesos.sp_RegistrarUsuario;
GO

CREATE PROCEDURE Procesos.sp_RegistrarUsuario
    @nombreUsuario          VARCHAR(50),
    @apellidoUsuario        VARCHAR(50),
    @segundoNombreUsuario   VARCHAR(50) = NULL,
    @segundoApellidoUsuario VARCHAR(50) = NULL,
    @correoUsuario          VARCHAR(50),
    @fechaRegistroUsuario   DATE,
    @passwordHash           VARCHAR(255)
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (SELECT 1 FROM Seguridad.Usuario WHERE correoUsuario = @correoUsuario)
        THROW 50001, 'El correo ingresado ya se encuentra registrado.', 1;

    IF LEN(LTRIM(RTRIM(@passwordHash))) < 8
        THROW 50030, 'El hash de contraseña no es válido.', 1;

    DECLARE @idUsuario INT = NEXT VALUE FOR dbo.seq_Usuario;   -- sin race condition

        idUsuario, nombreUsuario, apellidoUsuario,
        segundoNombreUsuario, segundoApellidoUsuario,
        correoUsuario, fechaRegistroUsuario, passwordHash
    )
    VALUES
    (
        @idUsuario, @nombreUsuario, @apellidoUsuario,
        @segundoNombreUsuario, @segundoApellidoUsuario,
        @correoUsuario, @fechaRegistroUsuario, @passwordHash
    );

    SELECT 'Usuario registrado correctamente' AS Mensaje, @idUsuario AS idUsuario;
END;
GO


-- sp_InsertarArtista con SEQUENCE
DROP PROCEDURE IF EXISTS Procesos.sp_InsertarArtista;
