CREATE PROCEDURE Procesos.sp_InsertarArtista
    @nombreArtista           VARCHAR(50),
    @paisOrigenArtista       VARCHAR(50),
    @descripcionArtista      VARCHAR(50) = NULL,
    @Productora_idProductora INT
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM Catalogo.Productora WHERE idProductora = @Productora_idProductora)
        THROW 50101, 'La productora especificada no existe.', 1;
    IF EXISTS (SELECT 1 FROM Catalogo.Artista WHERE nombreArtista = @nombreArtista)
        THROW 50107, 'Ya existe un artista con ese nombre.', 1;

    DECLARE @idArtista INT = NEXT VALUE FOR dbo.seq_Artista;

    VALUES (@idArtista, @nombreArtista, @paisOrigenArtista, @descripcionArtista, @Productora_idProductora);

    SELECT 'Artista registrado correctamente' AS Mensaje, @idArtista AS idArtista;
END;
GO


-- sp_CrearPlaylist con SEQUENCE
DROP PROCEDURE IF EXISTS Procesos.sp_CrearPlaylist;
