    SELECT 'Pago registrado correctamente' AS Mensaje, @idPago AS idPago;
END;
GO


/* -- 
   GAP 4 — sp_ActualizarReproduccion faltante
   Problema : Reproduccion no tenía SP de UPDATE, dejando el
              CRUD incompleto (afecta rúbrica "operaciones CRUD").
   Solución : Crear el SP. En la práctica una reproducción
              puede necesitar corregir su duración o fecha
              (error de registro, datos de prueba, etc.).
   --  */

CREATE PROCEDURE Procesos.sp_ActualizarReproduccion
    @idReproduccion       INT,
    @fechaReproduccion    DATE,
    @duracionReproduccion FLOAT
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (
        SELECT 1 FROM Interaccion.Reproduccion
        WHERE idReproduccion = @idReproduccion
    )
        THROW 50050, 'La reproduccion especificada no existe.', 1;

    IF @duracionReproduccion < 0
        THROW 50051, 'La duracion de reproduccion no puede ser negativa.', 1;

    -- El trigger trg_ValidarDuracionReproduccion valida que no supere
    -- la duración total de la canción, así que no necesitamos repetirlo aquí.
    UPDATE Interaccion.Reproduccion
    SET fechaReproduccion    = @fechaReproduccion,
        duracionReproduccion = @duracionReproduccion
    WHERE idReproduccion = @idReproduccion;

    SELECT 'Reproduccion actualizada correctamente' AS Mensaje;
END;
GO

