USE SonoraInc;
GO

IF NOT EXISTS (
    SELECT 1 FROM sys.columns
    WHERE object_id = OBJECT_ID('Seguridad.Usuario')
      AND name = 'rolUsuario'
)
BEGIN
    ALTER TABLE Seguridad.Usuario
        ADD rolUsuario VARCHAR(20) NOT NULL DEFAULT 'usuario';
END;
