IF NOT EXISTS (
    SELECT 1 FROM sys.check_constraints
    WHERE parent_object_id = OBJECT_ID('Seguridad.Usuario')
      AND name = 'CHK_rolUsuario'
)
BEGIN
    ALTER TABLE Seguridad.Usuario
        ADD CONSTRAINT CHK_rolUsuario
            CHECK (rolUsuario IN ('admin', 'usuario'));
END;
